const input = $input.first()?.json || {};
const payload = input.body && typeof input.body === 'object' ? input.body : input;

const normalize = (value, fallback = '') => {
  if (value === null || value === undefined) return fallback;
  const text = String(value).trim();
  return text || fallback;
};

const readEnv = (key, fallback = '') => {
  try {
    const envObject = typeof $env === 'object' && $env ? $env : null;
    if (envObject) {
      const envValue = envObject[key];
      if (envValue !== undefined && envValue !== null) {
        return normalize(envValue, fallback);
      }
    }
  } catch {}
  try {
    if (typeof process !== 'undefined' && process && process.env) {
      const processValue = process.env[key];
      if (processValue !== undefined && processValue !== null) {
        return normalize(processValue, fallback);
      }
    }
  } catch {}
  return fallback;
};

const safeInt = (value, fallback = 0) => {
  const parsed = Number.parseInt(String(value ?? ''), 10);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const clip = (value, max = 12000) => {
  const text = normalize(value);
  return text.length > max ? text.slice(0, max) : text;
};

const splitUserPoints = (text, maxItems = 10) => {
  const raw = clip(text, 12000);
  if (!raw) return [];
  const lines = raw.split(/\r?\n/).map((line) => line.replace(/^[-*\d.)\s]+/, '').trim()).filter(Boolean);
  const unique = [];
  for (const line of lines) {
    if (!unique.includes(line)) unique.push(line);
    if (unique.length >= maxItems) break;
  }
  return unique;
};

const numeroProcesso = normalize(payload.numero_processo);
const autor = normalize(payload.autor);
const reu = normalize(payload.reu, 'Nao informado');
const tipoAcao = normalize(payload.tipo_acao);
const fatos = clip(payload.fatos, 12000);
const pedidoAutor = clip(payload.pedido_autor, 8000);
const textoEditadoAoVivo = clip(payload.texto_editado_ao_vivo, 12000);
const arquivoNome = normalize(payload.arquivo_base_nome || payload.arquivo_base);
const arquivoMime = normalize(payload.arquivo_base_mime_type, 'application/octet-stream');
const arquivoTamanhoBytes = safeInt(payload.arquivo_base_tamanho_bytes, 0);
const arquivoConteudoBase64 = normalize(payload.arquivo_base_conteudo_base64);
const modeloMaeTexto = clip(payload.modelo_mae_texto || readEnv('MODELO_MAE_CONTESTACAO'), 15000);

const inferTextFromFile = () => {
  if (!arquivoConteudoBase64) return '';
  const lowerName = arquivoNome.toLowerCase();
  const isTextLike = arquivoMime.startsWith('text/') || /\.(txt|md|json|csv|xml|html|htm|rtf)$/i.test(lowerName);
  if (!isTextLike) return '';
  try {
    return Buffer.from(arquivoConteudoBase64, 'base64').toString('utf8').replace(/\0/g, '').slice(0, 15000);
  } catch { return ''; }
};

const textoPeticaoBase = inferTextFromFile();
const pontosUsuario = splitUserPoints(textoEditadoAoVivo, 10);

const errors = [];
if (!numeroProcesso) errors.push('numero_processo obrigatorio');
if (!autor) errors.push('autor obrigatorio');
if (!tipoAcao) errors.push('tipo_acao obrigatorio');
if (!fatos) errors.push('fatos obrigatorio');
if (!pedidoAutor) errors.push('pedido_autor obrigatorio');

const cnjRegex = /^\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4}$/;
if (numeroProcesso && !cnjRegex.test(numeroProcesso)) {
  errors.push('numero_processo fora do padrao CNJ 0001234-56.2026.8.00.0000');
}
if (arquivoNome && !arquivoConteudoBase64) errors.push('arquivo_base_conteudo_base64 obrigatorio quando arquivo_base_nome for enviado');
if (arquivoConteudoBase64 && !arquivoNome) errors.push('arquivo_base_nome obrigatorio quando arquivo_base_conteudo_base64 for enviado');
if (arquivoTamanhoBytes > 10 * 1024 * 1024) errors.push('arquivo_base excede o tamanho maximo de 10MB');
if (arquivoNome && !/\.(pdf|doc|docx|txt|md|rtf)$/i.test(arquivoNome)) errors.push('arquivo_base deve ser PDF, DOC, DOCX, TXT, MD ou RTF');

const regrasAplicadas = [
  'Trigger webhook POST /contestacao ativo',
  'Validacao de campos obrigatorios e formato CNJ',
  'Normalizacao de payload para o agente de IA',
  'Leitura de contexto do usuario (texto_editado_ao_vivo)',
  'Suporte a modelo-mae (payload ou env MODELO_MAE_CONTESTACAO)',
  'Leitura best-effort de peticao base textual (quando arquivo for texto)',
];

if (errors.length) {
  return [{ json: { status: 'erro_validacao', mensagem: 'Falha de validacao no trigger Webhook Contestacao.', erros: errors, regras_aplicadas: regrasAplicadas, gatilhos_acionados: [{ tipo: 'webhook', metodo: 'POST', path: 'contestacao' }], recebido_em: new Date().toISOString() } }];
}

return [{ json: { status: 'entrada_validada', mensagem: 'Entrada validada para processamento do agente de IA.', regras_aplicadas: regrasAplicadas, gatilhos_acionados: [{ tipo: 'webhook', metodo: 'POST', path: 'contestacao' }], contexto: { numero_processo: numeroProcesso, autor, reu, tipo_acao: tipoAcao, fatos, pedido_autor: pedidoAutor, texto_editado_ao_vivo: textoEditadoAoVivo, modo_ia: normalize(payload.modo_ia), openai_free_test_mode: payload.openai_free_test_mode === true || String(payload.openai_free_test_mode || '').toLowerCase() === 'true', pontos_usuario: pontosUsuario, modelo_mae_texto: modeloMaeTexto, arquivo_base: { nome: arquivoNome, mime_type: arquivoMime, tamanho_bytes: arquivoTamanhoBytes, conteudo_texto: textoPeticaoBase } }, recebido_em: new Date().toISOString() } }];

const envelope = $input.first()?.json || {};
if (envelope.status === 'erro_validacao') return [{ json: envelope }];

const contexto = envelope.contexto && typeof envelope.contexto === 'object' ? envelope.contexto : {};
const textoLivre = `${contexto.texto_editado_ao_vivo || ''} ${contexto.fatos || ''}`.toLowerCase();

const prioridade = /urgente|liminar|prazo hoje|prazo final|24h|48h/.test(textoLivre) ? 'alta' : /prioridade media|sem urgencia/.test(textoLivre) ? 'media' : 'normal';
const complexidade = (contexto.fatos || '').length > 2500 || (contexto.pontos_usuario || []).length >= 6 ? 'alta' : (contexto.fatos || '').length > 900 ? 'media' : 'baixa';
const categoria = (contexto.tipo_acao || '').trim() || 'Nao informado';
const scoreRisco = (prioridade === 'alta' ? 50 : prioridade === 'media' ? 30 : 15) + (complexidade === 'alta' ? 35 : complexidade === 'media' ? 20 : 10);

const regras = Array.isArray(envelope.regras_aplicadas) ? envelope.regras_aplicadas : [];
regras.push('Classificacao de prioridade e complexidade da entrada');
regras.push('Auditoria de versao do workflow v3 - Claude AI');

return [{ json: { ...envelope, regras_aplicadas: regras, classificacao: { prioridade, complexidade, categoria, score_risco: Math.min(scoreRisco, 100) }, auditoria_execucao: { workflow_version: 'v3.1.0-claude', classificado_em: new Date().toISOString() } } }];

const envelope = $input.first()?.json || {};
if (envelope.status === 'erro_validacao') return [{ json: envelope }];

const contexto = envelope.contexto && typeof envelope.contexto === 'object' ? envelope.contexto : {};
const tipoAcao = (contexto.tipo_acao || '').trim();
const numeroProcessoAtual = (contexto.numero_processo || '').trim();

const normalize = (value, fallback = '') => {
  if (value === null || value === undefined) return fallback;
  const text = String(value).trim();
  return text || fallback;
};

const readEnv = (key, fallback = '') => {
  try {
    const envObject = typeof $env === 'object' && $env ? $env : null;
    if (envObject) { const v = envObject[key]; if (v !== undefined && v !== null) return normalize(v, fallback); }
  } catch {}
  try {
    if (typeof process !== 'undefined' && process && process.env) { const v = process.env[key]; if (v !== undefined && v !== null) return normalize(v, fallback); }
  } catch {}
  return fallback;
};

const SUPABASE_URL = normalize(readEnv('SUPABASE_URL')).replace(/\/+$/, '');
const SUPABASE_KEY = normalize(readEnv('SUPABASE_PUBLISHABLE_KEY') || readEnv('SUPABASE_ANON_KEY') || readEnv('SUPABASE_SERVICE_ROLE_KEY'));

const regras = Array.isArray(envelope.regras_aplicadas) ? [...envelope.regras_aplicadas] : [];
let defesasAnteriores = [];
let consultaStatus = 'nao_executada';
let consultaDetalhe = '';

if (!SUPABASE_URL || !SUPABASE_KEY) {
  consultaStatus = 'sem_credenciais';
  consultaDetalhe = 'SUPABASE_URL ou SUPABASE_PUBLISHABLE_KEY nao configuradas no ambiente do n8n.';
  regras.push('Consulta de defesas anteriores ignorada: credenciais Supabase ausentes');
} else {
  let timeoutHandle;
  try {
    const queryParams = new URLSearchParams({ select: 'numero_processo,tipo_acao,fatos,pedido_autor,n8n_resposta,status,criado_em', status: 'eq.ok', order: 'criado_em.desc', limit: '5' });
    if (tipoAcao) queryParams.set('tipo_acao', `eq.${tipoAcao}`);
    if (numeroProcessoAtual) queryParams.set('numero_processo', `neq.${numeroProcessoAtual}`);

    const url = `${SUPABASE_URL}/rest/v1/contestacoes?${queryParams.toString()}`;
    const controller = new AbortController();
    timeoutHandle = setTimeout(() => controller.abort(), 8000);

    const response = await fetch(url, { method: 'GET', headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=representation' }, signal: controller.signal });

    if (!response.ok) {
      consultaStatus = 'erro_http';
      consultaDetalhe = `HTTP ${response.status} ao consultar Supabase REST API.`;
      regras.push(`Consulta de defesas anteriores falhou: HTTP ${response.status}`);
    } else {
      const data = await response.json().catch(() => []);
      if (Array.isArray(data) && data.length > 0) {
        defesasAnteriores = data.map((row) => {
          const n8nResp = row.n8n_resposta && typeof row.n8n_resposta === 'object' ? row.n8n_resposta : {};
          const minuta = n8nResp.minuta && typeof n8nResp.minuta === 'object' ? n8nResp.minuta : {};
          return { numero_processo: normalize(row.numero_processo), tipo_acao: normalize(row.tipo_acao), fatos_resumo: normalize(row.fatos).slice(0, 500), pedido_autor_resumo: normalize(row.pedido_autor).slice(0, 300), tese_central: normalize(minuta.tese_central), resumo_estrategico: normalize(minuta.resumo_estrategico), riscos: Array.isArray(minuta.riscos) ? minuta.riscos.slice(0, 3) : [], criado_em: normalize(row.criado_em) };
        });
        consultaStatus = 'sucesso';
        consultaDetalhe = `${defesasAnteriores.length} defesa(s) anterior(es) encontrada(s) para ${tipoAcao || 'todos os tipos'}.`;
        regras.push(`Contexto historico carregado: ${defesasAnteriores.length} defesas anteriores similares`);
      } else {
        consultaStatus = 'sem_resultados';
        consultaDetalhe = `Nenhuma defesa concluida encontrada para tipo_acao=${tipoAcao || 'qualquer'}.`;
        regras.push('Consulta de defesas anteriores: nenhum caso similar encontrado no banco');
      }
    }
  } catch (error) {
    consultaStatus = 'erro_conexao';
    consultaDetalhe = normalize(error?.message, 'Erro ao conectar com Supabase').slice(0, 200);
    regras.push('Consulta de defesas anteriores falhou: erro de conexao com Supabase');
  } finally {
    if (timeoutHandle) clearTimeout(timeoutHandle);
  }
}

return [{ json: { ...envelope, regras_aplicadas: regras, defesas_anteriores: { status: consultaStatus, detalhe: consultaDetalhe, casos: defesasAnteriores, total: defesasAnteriores.length } } }];

// =============================================================
// Agente IA Contestacao v3.1 - Claude AI (Anthropic) pre-configurado
// Prioridade: 1) Claude API  2) OpenAI API  3) Fallback local (teste)
// =============================================================

const envelope = $input.first()?.json || {};
if (envelope.status === 'erro_validacao') return [{ json: envelope }];

const contexto = envelope.contexto && typeof envelope.contexto === 'object' ? envelope.contexto : {};
const classificacaoEntrada = envelope.classificacao && typeof envelope.classificacao === 'object' ? envelope.classificacao : {};
const auditoriaExecucao = envelope.auditoria_execucao && typeof envelope.auditoria_execucao === 'object' ? envelope.auditoria_execucao : {};
const defesasAnteriores = envelope.defesas_anteriores && typeof envelope.defesas_anteriores === 'object' ? envelope.defesas_anteriores : { status: 'nao_disponivel', casos: [], total: 0 };

const normalize = (value, fallback = '') => {
  if (value === null || value === undefined) return fallback;
  const text = String(value).trim();
  return text || fallback;
};

const readEnv = (key, fallback = '') => {
  try {
    const envObject = typeof $env === 'object' && $env ? $env : null;
    if (envObject) { const v = envObject[key]; if (v !== undefined && v !== null) return normalize(v, fallback); }
  } catch {}
  try {
    if (typeof process !== 'undefined' && process && process.env) { const v = process.env[key]; if (v !== undefined && v !== null) return normalize(v, fallback); }
  } catch {}
  return fallback;
};

const clip = (value, max = 16000) => {
  const text = normalize(value);
  return text.length > max ? text.slice(0, max) : text;
};

// --- Dados do caso ---
const numeroProcesso = normalize(contexto.numero_processo);
const autor = normalize(contexto.autor);
const reu = normalize(contexto.reu, 'Nao informado');
const tipoAcao = normalize(contexto.tipo_acao);
const fatos = clip(contexto.fatos, 12000);
const pedidoAutor = clip(contexto.pedido_autor, 8000);
const textoEditado = clip(contexto.texto_editado_ao_vivo, 12000);
const pontosUsuario = Array.isArray(contexto.pontos_usuario) ? contexto.pontos_usuario.map((item) => normalize(item)).filter(Boolean).slice(0, 10) : [];
const modeloMaeTexto = clip(contexto.modelo_mae_texto, 15000);
const textoPeticaoBase = clip(contexto?.arquivo_base?.conteudo_texto, 15000);
const arquivoNome = normalize(contexto?.arquivo_base?.nome);

const regrasAplicadas = Array.isArray(envelope.regras_aplicadas) ? [...envelope.regras_aplicadas] : [];
regrasAplicadas.push('Aplicacao de regras juridicas de contestacao civil');
regrasAplicadas.push('Priorizacao dos pontos pedidos pelo usuario');
regrasAplicadas.push('Uso de modelo-mae quando disponivel');
regrasAplicadas.push('Persistencia de dados delegada ao backend PostgreSQL/Supabase');
regrasAplicadas.push('Contexto de rotas e arquitetura do sistema injetado no agente');
regrasAplicadas.push('Defesas anteriores similares consultadas no banco');

const gatilhosAcionados = Array.isArray(envelope.gatilhos_acionados) ? envelope.gatilhos_acionados : [{ tipo: 'webhook', metodo: 'POST', path: 'contestacao' }];

// =============================================================
// Configuracao de providers IA (Claude primeiro, OpenAI fallback)
// =============================================================

// Claude (Anthropic) - PROVIDER PRINCIPAL
const ANTHROPIC_API_KEY = normalize(
  readEnv('ANTHROPIC_API_KEY') || readEnv('CLAUDE_API_KEY') || readEnv('CLAUDE_SECRET_KEY'),
);
const CLAUDE_MODEL = normalize(
  readEnv('CLAUDE_MODEL') || readEnv('ANTHROPIC_MODEL'),
  'claude-sonnet-4-6',
);
const ANTHROPIC_BASE_URL = normalize(
  readEnv('ANTHROPIC_BASE_URL') || readEnv('CLAUDE_BASE_URL'),
  'https://api.anthropic.com',
).replace(/\/+$/, '');
const ANTHROPIC_VERSION = normalize(readEnv('ANTHROPIC_VERSION'), '2023-06-01');

// OpenAI - PROVIDER SECUNDARIO (fallback)
const OPENAI_API_KEY = normalize(
  readEnv('OPENAI_API_KEY') || readEnv('OPENAI_KEY') || readEnv('OPENAI_SECRET_KEY'),
);
const OPENAI_MODEL = normalize(
  readEnv('OPENAI_MODEL') || readEnv('OPENAI_RESPONSES_MODEL') || readEnv('OPENAI_CHAT_MODEL'),
  'gpt-4o',
);
const OPENAI_BASE_URL = normalize(
  readEnv('OPENAI_BASE_URL') || readEnv('OPENAI_API_BASE_URL'),
  'https://api.openai.com/v1',
).replace(/\/+$/, '');

// Configuracoes compartilhadas
const MAX_TOKENS = Math.max(700, Number.parseInt(readEnv('CLAUDE_MAX_TOKENS') || readEnv('OPENAI_MAX_OUTPUT_TOKENS') || '4096', 10) || 4096);
const TIMEOUT_MS = Math.max(10000, Number.parseInt(readEnv('CLAUDE_TIMEOUT_MS') || readEnv('OPENAI_TIMEOUT_MS') || '45000', 10) || 45000);
const TEMPERATURE_RAW = Number.parseFloat(readEnv('CLAUDE_TEMPERATURE') || readEnv('OPENAI_TEMPERATURE') || '0.12');
const TEMPERATURE = Number.isFinite(TEMPERATURE_RAW) ? Math.min(Math.max(TEMPERATURE_RAW, 0), 1) : 0.12;

const DB_PROVIDER = normalize(readEnv('CONTESTACAO_DB_PROVIDER'), 'backend_postgresql_supabase');
const DB_TABLE = normalize(readEnv('CONTESTACAO_DB_TABLE'), 'contestacoes');
const DB_STATUS_FIELD = normalize(readEnv('CONTESTACAO_DB_STATUS_FIELD'), 'status');

// Determina qual provider esta ativo
const activeProvider = ANTHROPIC_API_KEY ? 'claude' : OPENAI_API_KEY ? 'openai' : 'fallback_local';
const activeModel = activeProvider === 'claude' ? CLAUDE_MODEL : activeProvider === 'openai' ? OPENAI_MODEL : 'deterministico';

const requestedMode = normalize(contexto.modo_ia).toLowerCase();
const payloadFreeTestMode = contexto.openai_free_test_mode === true || requestedMode === 'teste_gratis';
const envFreeTestMode = normalize(readEnv('OPENAI_FREE_TEST_MODE'), 'false').toLowerCase() === 'true';
const FREE_TEST_MODE = payloadFreeTestMode || envFreeTestMode;

// --- Contexto de defesas anteriores ---
const casosAnteriores = Array.isArray(defesasAnteriores.casos) ? defesasAnteriores.casos : [];
let defesasAnteriorTexto = '';
if (casosAnteriores.length > 0) {
  const resumos = casosAnteriores.map((caso, i) => {
    const parts = [`Caso ${i + 1}: ${caso.numero_processo} (${caso.tipo_acao})`, `  Fatos resumo: ${caso.fatos_resumo}`, `  Pedido autor: ${caso.pedido_autor_resumo}`, `  Tese central usada: ${caso.tese_central}`, `  Estrategia: ${caso.resumo_estrategico}`];
    if (caso.riscos && caso.riscos.length > 0) parts.push(`  Riscos identificados: ${caso.riscos.join('; ')}`);
    return parts.join('\n');
  });
  defesasAnteriorTexto = '\n\nDEFESAS_ANTERIORES_SIMILARES (do banco de dados, mesmo tipo_acao, para referencia):\n' + resumos.join('\n\n');
}

// =============================================================
// Funcao de fallback local (modo teste / sem API key)
// =============================================================
const buildFallbackDraft = (reason = 'fallback_local') => {
  const pontosUsuarioTexto = pontosUsuario.length ? `Pontos solicitados pelo usuario: ${pontosUsuario.join('; ')}.` : 'Sem pontos adicionais informados pelo usuario.';
  const sintese = `Trata-se de contestacao referente ao processo ${numeroProcesso}, proposta por ${autor} em face de ${reu}, no contexto de ${tipoAcao}.`;
  const fundamentos = `Com base nos fatos informados (${fatos}), impugna-se a narrativa autoral e requer-se a improcedencia dos pedidos, preservando contraditorio e ampla defesa. ${pontosUsuarioTexto}`;
  const pedidos = `Requer-se: (i) recebimento da contestacao; (ii) improcedencia dos pedidos autorais (${pedidoAutor}); (iii) producao de provas em direito admitidas.`;
  const observacoesModelo = modeloMaeTexto ? 'Modelo-mae identificado e sinalizado para revisao humana.' : 'Sem modelo-mae explicito. Estrutura padrao aplicada.';

  let referenciaAnterior = '';
  if (casosAnteriores.length > 0) {
    const teses = casosAnteriores.map(c => c.tese_central).filter(Boolean);
    if (teses.length > 0) referenciaAnterior = `\n\nReferencia de teses anteriores similares: ${teses.join('; ')}.`;
  }

  const minutaBase = ['I - Sintese da Demanda', sintese, '', 'II - Fundamentos de Defesa', fundamentos + referenciaAnterior, '', 'III - Pedidos', pedidos, '', textoEditado ? 'IV - Pontos do Usuario\n' + textoEditado : '', textoPeticaoBase ? 'V - Trechos da Peticao Base (analise textual)\n' + textoPeticaoBase.slice(0, 1500) : '', 'VI - Observacoes', observacoesModelo].filter(Boolean).join('\n\n');

  return { json: { status: 'ok', mensagem: 'Contestacao processada em modo fallback local (teste).', numero_processo: numeroProcesso, protocolo_n8n: `N8N-${Date.now()}`, gatilhos_acionados: gatilhosAcionados, regras_aplicadas: [...regrasAplicadas, 'Fallback local sem chamada externa (modo teste)'], engine_ia: { provider: 'fallback_local', model: 'deterministico', motivo: reason, providers_disponiveis: { claude: Boolean(ANTHROPIC_API_KEY), openai: Boolean(OPENAI_API_KEY) } }, classificacao: classificacaoEntrada, auditoria_execucao: auditoriaExecucao, infra: { modelo_configurado: activeModel, banco_provider: DB_PROVIDER, banco_tabela: DB_TABLE, banco_campo_status: DB_STATUS_FIELD, persistencia: 'realizada_no_backend' }, defesas_anteriores: { consultadas: casosAnteriores.length, status: defesasAnteriores.status }, minuta: { texto_base: minutaBase, secoes: { sintese, fundamentos: fundamentos + referenciaAnterior, pedidos }, resumo_estrategico: 'Minuta base gerada localmente para revisao humana.', tese_central: 'Impugnacao dos pedidos autorais e pedido de improcedencia.', pontos_atendidos: pontosUsuario, riscos: ['Sem IA externa ativa: revisar fundamentacao legal manualmente.'] }, auditoria: { modelo_mae_utilizado: Boolean(modeloMaeTexto), peticao_base_lida: Boolean(textoPeticaoBase), pontos_usuario_identificados: pontosUsuario.length, defesas_anteriores_consultadas: casosAnteriores.length, arquivo_base_nome: arquivoNome || '' }, contexto: { autor, reu, tipo_acao: tipoAcao }, recebido_em: new Date().toISOString() } };
};

// Modo teste gratis -> fallback local
if (FREE_TEST_MODE) return [buildFallbackDraft('modo_teste_gratis')];

// Sem nenhuma API key -> fallback local
if (!ANTHROPIC_API_KEY && !OPENAI_API_KEY) return [buildFallbackDraft('nenhuma_api_key_configurada')];

// =============================================================
// System prompt enriquecido com rotas, banco e defesas
// =============================================================
const systemPrompt = [
  'Voce e um agente juridico especialista em contestacoes civeis no Brasil, integrado ao sistema AutoJuri.',
  '',
  'CONTEXTO DO SISTEMA AUTOJURI:',
  '- Backend: FastAPI na porta 8000.',
  '- Frontend: React + Vite na porta 5173.',
  '- Automacao: n8n na porta 5678 (este workflow).',
  '- Banco de dados: PostgreSQL hospedado no Supabase.',
  '- Autenticacao: Supabase Auth com Bearer token JWT.',
  '',
  'ROTAS DO BACKEND:',
  '- POST /api/gerar-contestacao -> envia caso para este workflow n8n e persiste no banco.',
  '- GET /api/contestacoes/resumo -> retorna cards e historico do dashboard do usuario.',
  '- POST /api/usuarios/cadastro -> cadastro de novo usuario.',
  '- POST /api/usuarios/login -> login com cookie HTTPOnly.',
  '- POST /api/usuarios/logout -> logout e revogacao de sessao.',
  '- GET /api/usuarios/sessao -> valida sessao ativa.',
  '- POST /api/suporte/contato -> canal de reclamacao do usuario.',
  '',
  'SCHEMA DO BANCO (tabela contestacoes):',
  '- id (BIGSERIAL PK), usuario_id, numero_processo, autor, reu, tipo_acao,',
  '- fatos, pedido_autor, arquivo_base, texto_editado_ao_vivo,',
  '- status (ok|processando|erro|erro_validacao|rejeitado),',
  '- n8n_resposta (JSONB), criado_em (TIMESTAMPTZ).',
  '',
  'PAGINAS DO FRONTEND: Inicio, Painel (formulario+upload+editor), Dashboard (cards+historico), Suporte.',
  '',
  'SUA TAREFA:',
  'Redigir minuta de contestacao para revisao humana.',
  'Regras: objetividade, clareza, sem inventar fatos, sem inventar jurisprudencia ou citacoes numericas.',
  'Se MODELO_MAE existir, preserve estilo e estrutura do modelo.',
  'Se TEXTO_PETICAO_BASE existir, identifique pontos centrais e responda tecnicamente.',
  'Priorize pontos do usuario em texto_editado_ao_vivo.',
  '',
  'Se houver DEFESAS_ANTERIORES_SIMILARES, use como referencia de estilo e tese (sem copiar ipsis litteris).',
  '',
  'Responda SOMENTE JSON valido com as chaves:',
  '{"resumo_estrategico":"...","tese_central":"...","pontos_atendidos":["..."],"sintese":"...","fundamentos":"...","pedidos":"...","observacoes":"...","riscos":["..."]}',
  'Nao use markdown.',
].join('\n');

const userPayload = { numero_processo: numeroProcesso, autor, reu, tipo_acao: tipoAcao, fatos, pedido_autor: pedidoAutor, pontos_usuario: pontosUsuario, texto_editado_ao_vivo: textoEditado, texto_peticao_base: textoPeticaoBase, modelo_mae_texto: modeloMaeTexto, classificacao: classificacaoEntrada };
let userMessageText = `CASO_JSON:\n${JSON.stringify(userPayload, null, 2)}`;
if (defesasAnteriorTexto) userMessageText += defesasAnteriorTexto;

const stripMarkdownFences = (value) => {
  const trimmed = normalize(value);
  if (!trimmed.startsWith('```')) return trimmed;
  return trimmed.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
};
const parseModelJson = (value) => JSON.parse(stripMarkdownFences(value));

// =============================================================
// Chamada para a API de IA (Claude ou OpenAI)
// =============================================================
let rawModelText = '';
let usedProvider = activeProvider;

const controller = new AbortController();
const timeoutHandle = setTimeout(() => controller.abort(), TIMEOUT_MS);

try {
  if (activeProvider === 'claude') {
    // ===================== CLAUDE API (Anthropic Messages) =====================
    const requestBody = {
      model: CLAUDE_MODEL,
      max_tokens: MAX_TOKENS,
      temperature: TEMPERATURE,
      system: systemPrompt,
      messages: [{ role: 'user', content: userMessageText }],
    };

    const response = await fetch(`${ANTHROPIC_BASE_URL}/v1/messages`, {
      method: 'POST',
      headers: {
        'x-api-key': ANTHROPIC_API_KEY,
        'anthropic-version': ANTHROPIC_VERSION,
        'content-type': 'application/json',
      },
      body: JSON.stringify(requestBody),
      signal: controller.signal,
    });

    const payload = await response.json().catch(() => ({}));

    if (!response.ok) {
      const detail = normalize(payload?.error?.message) || `HTTP_${response.status}`;
      throw new Error(`Claude API falhou: ${detail}`);
    }

    // Extrai texto da resposta Claude
    if (Array.isArray(payload?.content)) {
      for (const block of payload.content) {
        if (block?.type === 'text' && block?.text) rawModelText += block.text;
      }
    }
    usedProvider = 'claude';

  } else {
    // ===================== OPENAI API (Responses) =====================
    const requestBody = {
      model: OPENAI_MODEL,
      temperature: TEMPERATURE,
      max_output_tokens: MAX_TOKENS,
      input: [
        { role: 'system', content: [{ type: 'input_text', text: systemPrompt }] },
        { role: 'user', content: [{ type: 'input_text', text: userMessageText }] },
      ],
    };

    const response = await fetch(`${OPENAI_BASE_URL}/responses`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${OPENAI_API_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(requestBody),
      signal: controller.signal,
    });

    const payload = await response.json().catch(() => ({}));

    if (!response.ok) {
      const detail = normalize(payload?.error?.message) || `HTTP_${response.status}`;
      throw new Error(`OpenAI API falhou: ${detail}`);
    }

    if (typeof payload?.output_text === 'string' && payload.output_text.trim()) rawModelText = payload.output_text;
    if (Array.isArray(payload?.output)) {
      for (const block of payload.output) {
        if (!Array.isArray(block?.content)) continue;
        for (const ci of block.content) {
          const t = normalize(ci?.text) || normalize(ci?.output_text) || normalize(ci?.input_text);
          if (t) rawModelText += '\n' + t;
        }
      }
    }
    usedProvider = 'openai';
  }
} catch (error) {
  const reason = normalize(error?.message, 'erro_api').slice(0, 160);
  return [buildFallbackDraft(reason)];
} finally {
  clearTimeout(timeoutHandle);
}

rawModelText = rawModelText.trim();

if (!rawModelText) return [buildFallbackDraft('resposta_ia_sem_conteudo')];

let modelData = {};
try { modelData = parseModelJson(rawModelText); } catch { return [buildFallbackDraft('resposta_ia_nao_json')]; }

// =============================================================
// Monta resposta final estruturada
// =============================================================
const sinteseIa = clip(modelData.sintese, 10000) || `Trata-se de contestacao referente ao processo ${numeroProcesso}, proposta por ${autor} em face de ${reu}, no contexto de ${tipoAcao}.`;
const fundamentosIa = clip(modelData.fundamentos, 15000) || `Com base nos fatos informados (${fatos}), impugna-se a narrativa autoral e requer-se a improcedencia dos pedidos.`;
const pedidosIa = clip(modelData.pedidos, 8000) || `Requer-se o recebimento da contestacao e a improcedencia do pedido autoral (${pedidoAutor}).`;
const observacoesIa = clip(modelData.observacoes, 6000);
const resumoEstrategico = clip(modelData.resumo_estrategico, 3000) || 'Defesa gerada por IA para revisao humana.';
const teseCentral = clip(modelData.tese_central, 2000) || 'Improcedencia dos pedidos autorais.';
const pontosAtendidos = Array.isArray(modelData.pontos_atendidos) ? modelData.pontos_atendidos.map((item) => normalize(item)).filter(Boolean).slice(0, 12) : pontosUsuario;
const riscos = Array.isArray(modelData.riscos) ? modelData.riscos.map((item) => normalize(item)).filter(Boolean).slice(0, 6) : ['Revisar fundamentos e provas antes do protocolo.'];

const minutaBase = ['I - Sintese da Demanda', sinteseIa, '', 'II - Fundamentos de Defesa', fundamentosIa, '', 'III - Pedidos', pedidosIa, '', pontosUsuario.length ? 'IV - Pontos Solicitados pelo Usuario\n- ' + pontosUsuario.join('\n- ') : '', observacoesIa ? 'V - Observacoes do Agente de IA\n' + observacoesIa : '', riscos.length ? 'VI - Riscos e Pontos de Atencao\n- ' + riscos.join('\n- ') : ''].filter(Boolean).join('\n\n');

return [{ json: { status: 'ok', mensagem: `Contestacao processada pelo agente de IA (${usedProvider}) com regras completas e contexto historico.`, numero_processo: numeroProcesso, protocolo_n8n: `N8N-${Date.now()}`, gatilhos_acionados: gatilhosAcionados, regras_aplicadas: [...regrasAplicadas, `Resposta estruturada via ${usedProvider} (${activeModel})`], engine_ia: { provider: usedProvider, model: activeModel, endpoint: usedProvider === 'claude' ? `${ANTHROPIC_BASE_URL}/v1/messages` : `${OPENAI_BASE_URL}/responses`, temperature: TEMPERATURE, max_tokens: MAX_TOKENS }, classificacao: classificacaoEntrada, auditoria_execucao: { ...auditoriaExecucao, agente_ia_executado_em: new Date().toISOString() }, infra: { modelo_configurado: activeModel, banco_provider: DB_PROVIDER, banco_tabela: DB_TABLE, banco_campo_status: DB_STATUS_FIELD, persistencia: 'realizada_no_backend' }, defesas_anteriores: { consultadas: casosAnteriores.length, status: defesasAnteriores.status }, minuta: { texto_base: minutaBase, secoes: { sintese: sinteseIa, fundamentos: fundamentosIa, pedidos: pedidosIa }, resumo_estrategico: resumoEstrategico, tese_central: teseCentral, pontos_atendidos: pontosAtendidos, riscos }, auditoria: { modelo_mae_utilizado: Boolean(modeloMaeTexto), peticao_base_lida: Boolean(textoPeticaoBase), pontos_usuario_identificados: pontosUsuario.length, defesas_anteriores_consultadas: casosAnteriores.length, arquivo_base_nome: arquivoNome || '' }, contexto: { autor, reu, tipo_acao: tipoAcao }, recebido_em: new Date().toISOString() } }];
